import collections

def leastInterval(tasks: list[str], n: int) -> int:
    frequencies = collections.Counter(tasks)

    if not frequencies:
        return 0

    max_freq = max(frequencies.values())
    count_max_freq = 0
    for freq in frequencies.values():
        if freq == max_freq:
            count_max_freq += 1

    time_based_on_max_freq = (max_freq - 1) * (n + 1) + count_max_freq
    total_tasks = len(tasks)

    return max(total_tasks, time_based_on_max_freq)
